function log(message, color = colors.reset) {
  const timestamp = new Date().toISOString();
  console.log(`${colors.bold}[${timestamp}]${colors.reset} ${color}${message}${colors.reset}`);
}

function logStep(stepName) {
  const separator = '═'.repeat(60);
  console.log(`\n${colors.cyan}${separator}`);
  console.log(`  🚀 ${stepName}`);
  console.log(`${separator}${colors.reset}\n`);
  pipelineState.currentStep = stepName;
}

function logSuccess(message) {
  log(`✅ ${message}`, colors.green);
}

function logWarning(message) {
  log(`⚠️  ${message}`, colors.yellow);
}

function logError(message) {
  log(`❌ ${message}`, colors.red);
}

function logInfo(message) {
  log(`ℹ️  ${message}`, colors.blue);
}

function exec(command, options = {}) {
  const defaultOptions = {
    stdio: 'pipe',
    encoding: 'utf-8',
    timeout: CONFIG.testTimeout,
    env: { ...process.env, FORCE_COLOR: '1' },
  };
  const mergedOptions = { ...defaultOptions, ...options };

  try {
    const result = execSync(command, mergedOptions);
    return result ? result.trim() : '';
  } catch (error) {
    if (options.ignoreError) {
      return error.stdout ? error.stdout.trim() : '';
    }
    throw error;
  }
}

function execWithRetry(command, retries = CONFIG.maxRetries, delay = 5000) {
  for (let attempt = 1; attempt <= retries; attempt++) {
    try {
      return exec(command);
    } catch (error) {
      if (attempt === retries) {
        throw error;
      }
      logWarning(`Attempt ${attempt}/${retries} failed. Retrying in ${delay / 1000}s...`);
      execSync(`sleep ${delay / 1000}`);
    }
  }
}

function runAsync(command, options = {}) {
  return new Promise((resolve, reject) => {
    const child = spawn('sh', ['-c', command], {
      stdio: options.silent ? 'pipe' : 'inherit',
      env: { ...process.env, FORCE_COLOR: '1' },
      ...options,
    });

    let stdout = '';
    let stderr = '';

    if (child.stdout) {
      child.stdout.on('data', (data) => { stdout += data.toString(); });
    }
    if (child.stderr) {
      child.stderr.on('data', (data) => { stderr += data.toString(); });
    }

    child.on('close', (code) => {
      if (code === 0) {
        resolve({ stdout, stderr, code });
      } else {
        reject(new Error(`Command failed with code ${code}: ${command}\n${stderr}`));
      }
    });

    child.on('error', reject);
  });
}

async function runParallel(tasks) {
  return Promise.all(tasks.map((task) => {
    if (typeof task === 'function') return task();
    return runAsync(task, { silent: true });
  }));
}

function measureStep(stepName, fn) {
  const stepStart = Date.now();
  logStep(stepName);

  try {
    const result = fn();
    const duration = ((Date.now() - stepStart) / 1000).toFixed(2);
    logSuccess(`${stepName} completed in ${duration}s`);
    pipelineState.steps.push({ name: stepName, duration, status: 'success' });
    return result;
  } catch (error) {
    const duration = ((Date.now() - stepStart) / 1000).toFixed(2);
    logError(`${stepName} failed after ${duration}s`);
    pipelineState.steps.push({ name: stepName, duration, status: 'failed', error: error.message });
    pipelineState.errors.push({ step: stepName, error: error.message });
    throw error;
  }
}

async function measureStepAsync(stepName, fn) {
  const stepStart = Date.now();
  logStep(stepName);

  try {
    const result = await fn();
    const duration = ((Date.now() - stepStart) / 1000).toFixed(2);
    logSuccess(`${stepName} completed in ${duration}s`);
    pipelineState.steps.push({ name: stepName, duration, status: 'success' });
    return result;
  } catch (error) {
    const duration = ((Date.now() - stepStart) / 1000).toFixed(2);
    logError(`${stepName} failed after ${duration}s`);
    pipelineState.steps.push({ name: stepName, duration, status: 'failed', error: error.message });
    pipelineState.errors.push({ step: stepName, error: error.message });
    throw error;
  }
}

function fileExists(filePath) {
  try {
    fs.accessSync(filePath, fs.constants.F_OK);
    return true;
  } catch {
    return false;
  }
}

function getChecksum(filePath) {
  try {
    return exec(`sha256sum ${filePath} | cut -d' ' -f1`);
  } catch {
    return null;
  }
}

