function installDependencies() {
  measureStep('Install Dependencies', () => {
    const lockFile = fileExists('package-lock.json')
      ? 'package-lock.json'
      : fileExists('yarn.lock')
        ? 'yarn.lock'
        : fileExists('pnpm-lock.yaml')
          ? 'pnpm-lock.yaml'
          : null;

    logInfo(`Lock file: ${lockFile || 'none found'}`);

    // Check if we can skip install (cache hit)
    if (lockFile && fileExists('node_modules/.cache/lock-hash')) {
      const currentHash = getChecksum(lockFile);
      const cachedHash = fs.readFileSync('node_modules/.cache/lock-hash', 'utf-8').trim();
      if (currentHash === cachedHash) {
        logInfo('Dependencies unchanged - skipping install (cache hit)');
        return;
      }
    }

    let installCmd;
    let packageManager;

    if (lockFile === 'pnpm-lock.yaml') {
      packageManager = 'pnpm';
      installCmd = 'pnpm install --frozen-lockfile --prefer-offline';
    } else if (lockFile === 'yarn.lock') {
      packageManager = 'yarn';
      installCmd = 'yarn install --frozen-lockfile --prefer-offline';
    } else {
      packageManager = 'npm';
      installCmd = 'npm ci --prefer-offline --no-audit --no-fund';
    }

    logInfo(`Package manager: ${packageManager}`);
    logInfo(`Install command: ${installCmd}`);

    execWithRetry(installCmd);

    // Cache the lock hash for future runs
    if (lockFile) {
      const hash = getChecksum(lockFile);
      if (hash) {
        fs.mkdirSync('node_modules/.cache', { recursive: true });
        fs.writeFileSync('node_modules/.cache/lock-hash', hash);
      }
    }

    logSuccess('Dependencies installed');
  });
}

function runSecurityAudit() {
  measureStep('Security Audit', () => {
    try {
      const auditResult = exec('npm audit --json 2>/dev/null', { ignoreError: true });
      if (auditResult) {
        const audit = JSON.parse(auditResult);
        const vulnerabilities = audit.metadata?.vulnerabilities || {};
        const critical = vulnerabilities.critical || 0;
        const high = vulnerabilities.high || 0;
        const moderate = vulnerabilities.moderate || 0;

        logInfo(`Vulnerabilities - Critical: ${critical}, High: ${high}, Moderate: ${moderate}`);

        if (critical > 0) {
          logError(`Found ${critical} critical vulnerabilities!`);
          if (CONFIG.environment === 'production') {
            throw new Error('Critical vulnerabilities found. Aborting production deploy.');
          }
        }

        if (high > 0) {
          logWarning(`Found ${high} high severity vulnerabilities.`);
        }
      }
    } catch (error) {
      if (error.message.includes('Critical vulnerabilities')) {
        throw error;
      }
      logWarning('Security audit could not be completed. Continuing...');
    }

    logSuccess('Security audit completed');
  });
}

function runLinting() {
  measureStep('Lint Code', () => {
    const pkg = JSON.parse(fs.readFileSync('package.json', 'utf-8'));
    const scripts = pkg.scripts || {};

    if (scripts.lint) {
      exec('npm run lint', { stdio: 'inherit' });
      logSuccess('Linting passed');
    } else if (fileExists('.eslintrc.js') || fileExists('.eslintrc.json') || fileExists('.eslintrc.yml') || fileExists('eslint.config.js')) {
      exec('npx eslint . --max-warnings 0', { stdio: 'inherit' });
      logSuccess('ESLint passed');
    } else {
      logWarning('No linting configuration found. Skipping.');
    }
  });
}

function runTypeCheck() {
  measureStep('Type Check', () => {
    if (fileExists('tsconfig.json')) {
      const pkg = JSON.parse(fs.readFileSync('package.json', 'utf-8'));
      const scripts = pkg.scripts || {};

      if (scripts['type-check'] || scripts.typecheck) {
        const cmd = scripts['type-check'] ? 'npm run type-check' : 'npm run typecheck';
        exec(cmd, { stdio: 'inherit' });
      } else {
        exec('npx tsc --noEmit', { stdio: 'inherit' });
      }
      logSuccess('Type check passed');
    } else {
      logInfo('No tsconfig.json found. Skipping type check.');
    }
  });
}

async function runTests() {
  await measureStepAsync('Run Tests', async () => {
    const pkg = JSON.parse(fs.readFileSync('package.json', 'utf-8'));
    const scripts = pkg.scripts || {};

    if (!scripts.test || scripts.test.includes('no test specified')) {
      logWarning('No test script defined. Skipping tests.');
      return;
    }

    // Set up test environment
    const testEnv = {
      ...process.env,
      NODE_ENV: 'test',
      CI: 'true',
      FORCE_COLOR: '1',
    };

    // Run unit tests
    logInfo('Running unit tests...');
    try {
      await runAsync('npm test -- --ci --coverage --maxWorkers=50%', {
        env: testEnv,
        timeout: CONFIG.testTimeout,
      });
    } catch (error) {
      // Try without extra flags (not all test runners support them)
      logWarning('Test command with extra flags failed. Trying plain test command...');
      await runAsync('npm test', {
        env: testEnv,
        timeout: CONFIG.testTimeout,
      });
    }

    // Run integration tests if available
    if (scripts['test:integration']) {
      logInfo('Running integration tests...');
      await runAsync('npm run test:integration', {
        env: testEnv,
        timeout: CONFIG.testTimeout,
      });
    }

    // Run e2e tests if available
    if (scripts['test:e2e']) {
      logInfo('Running e2e tests...');
      await runAsync('npm run test:e2e', {
        env: testEnv,
        timeout: CONFIG.testTimeout * 2,
      });
    }

    // Check coverage thresholds
    if (fileExists('coverage/coverage-summary.json')) {
      try {
        const coverage = JSON.parse(fs.readFileSync('coverage/coverage-summary.json', 'utf-8'));
        const total = coverage.total;
        const thresholds = { lines: 80, branches: 70, functions: 80, statements: 80 };

        for (const [metric, threshold] of Object.entries(thresholds)) {
          const actual = total[metric]?.pct || 0;
          if (actual < threshold) {
            logWarning(`Coverage for ${metric}: ${actual}% (threshold: ${threshold}%)`);
          } else {
            logInfo(`Coverage for ${metric}: ${actual}%`);
          }
        }
      } catch {
        logInfo('Could not parse coverage report.');
      }
    }

    logSuccess('All tests passed');
  });
}

function buildApplication() {
  measureStep('Build Application', () => {
    const pkg = JSON.parse(fs.readFileSync('package.json', 'utf-8'));
    const scripts = pkg.scripts || {};

    if (!scripts.build) {
      logWarning('No build script defined. Skipping build.');
      return;
    }

    // Set production environment for build
    const buildEnv = {
      ...process.env,
      NODE_ENV: 'production',
      GENERATE_SOURCEMAP: CONFIG.environment === 'production' ? 'false' : 'true',
    };

    exec('npm run build', {
      stdio: 'inherit',
      env: buildEnv,
    });

    // Verify build output
    if (!fileExists(CONFIG.buildDir)) {
      // Check common build directories
      const altDirs = ['build', 'out', 'public', '.next'];
      const foundDir = altDirs.find((dir) => fileExists(dir));
      if (foundDir) {
        logInfo(`Build output found in: ${foundDir}`);
      } else {
        logWarning(`Build directory '${CONFIG.buildDir}' not found. Build may output elsewhere.`);
      }
    } else {
      const buildSize = exec(`du -sh ${CONFIG.buildDir} | cut -f1`);
      const fileCount = exec(`find ${CONFIG.buildDir} -type f | wc -l`).trim();
      logInfo(`Build size: ${buildSize}, Files: ${fileCount}`);
    }

    logSuccess('Build completed');
  });
}

function createArtifacts() {
  measureStep('Create Deployment Artifacts', () => {
    fs.mkdirSync(CONFIG.artifactDir, { recursive: true });

    const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
    const shortHash = pipelineState.commitHash.substring(0, 8);
    const artifactName = `deploy-${timestamp}-${shortHash}`;

    // Create build manifest
    const manifest = {
      version: JSON.parse(fs.readFileSync('package.json', 'utf-8')).version,
      commit: pipelineState.commitHash,
      branch: pipelineState.branch,
      timestamp: new Date().toISOString(),
      environment: CONFIG.environment,
      nodeVersion: exec('node --version'),
      buildSteps: pipelineState.steps,
    };

    fs.writeFileSync(
      path.join(CONFIG.artifactDir, 'manifest.json'),
      JSON.stringify(manifest, null, 2)
    );

    // Create tarball of build artifacts
    const buildDir = fileExists(CONFIG.buildDir) ? CONFIG.buildDir : '.';
    const tarFile = path.join(CONFIG.artifactDir, `${artifactName}.tar.gz`);

    const filesToInclude = [
      fileExists(CONFIG.buildDir) ? CONFIG.buildDir : '',
      'package.json',
      fileExists('package-lock.json') ? 'package-lock.json' : '',
      fileExists('.env.production') ? '.env.production' : '',
      fileExists('ecosystem.config.js') ? 'ecosystem.config.js' : '',
      fileExists('Dockerfile') ? 'Dockerfile' : '',
      fileExists('docker-compose.yml') ? 'docker-compose.yml' : '',
      path.join(CONFIG.artifactDir, 'manifest.json'),
    ].filter(Boolean).join(' ');

    exec(`tar -czf ${tarFile} ${filesToInclude}`);

    const artifactSize = exec(`du -sh ${tarFile} | cut -f1`);
    logInfo(`Artifact: ${tarFile} (${artifactSize})`);

    // Generate checksum
    const checksum = getChecksum(tarFile);
    fs.writeFileSync(`${tarFile}.sha256`, checksum);
    logInfo(`Checksum: ${checksum}`);

    logSuccess('Artifacts created');
    return tarFile;
  });
}

async function deployApplication() {
  await measureStepAsync('Deploy Application', async () => {
    logInfo(`Deploy target: ${CONFIG.deployTarget}`);
    logInfo(`Environment: ${CONFIG.environment}`);

    switch (CONFIG.deployTarget) {
      case 'remote':
        await deployRemote();
        break;
      case 'docker':
        await deployDocker();
        break;
      case 'local':
        await deployLocal();
        break;
      case 'pm2':
        await deployPM2();
        break;
      default:
        logWarning(`Unknown deploy target: ${CONFIG.deployTarget}. Using local deploy.`);
        await deployLocal();
    }

    logSuccess('Deployment completed');
  });
}

async function deployRemote() {
  const { deployHost, deployUser, deployPath } = CONFIG;
  const shortHash = pipelineState.commitHash.substring(0, 8);
  const releaseDir = `${deployPath}/releases/${Date.now()}-${shortHash}`;
  const currentLink = `${deployPath}/current`;

  logInfo(`Deploying to ${deployUser}@${deployHost}:${deployPath}`);

  // Store current deployment hash for rollback
  try {
    pipelineState.previousDeployHash = exec(
      `ssh ${deployUser}@${deployHost} "cat ${deployPath}/current/COMMIT_HASH 2>/dev/null"`,
      { ignoreError: true }
    );
  } catch {
    pipelineState.previousDeployHash = '';
  }

  // Create release directory
  exec(`ssh ${deployUser}@${deployHost} "mkdir -p ${releaseDir}"`);

  // Upload artifacts
  const artifactFiles = fs.readdirSync(CONFIG.artifactDir).filter((f) => f.endsWith('.tar.gz'));
  if (artifactFiles.length === 0) {
    throw new Error('No artifact found to deploy');
  }

  const artifactPath = path.join(CONFIG.artifactDir, artifactFiles[0]);
  logInfo(`Uploading ${artifactPath}...`);
  exec(`scp ${artifactPath} ${deployUser}@${deployHost}:${releaseDir}/`);

  // Extract and set up on remote
  const remoteCommands = `
    cd ${releaseDir} && \\
    tar -xzf *.tar.gz && \\
    rm -f *.tar.gz && \\
    npm ci --production --prefer-offline --no-audit --no-fund && \\
    echo "${pipelineState.commitHash}" > COMMIT_HASH && \\
    ln -sfn ${releaseDir} ${currentLink} && \\
    echo "Deployed successfully"
  `;

  exec(`ssh ${deployUser}@${deployHost} '${remoteCommands}'`, { stdio: 'inherit' });

  // Restart application
  const restartCommands = `
    cd ${currentLink} && \\
    if command -v pm2 &> /dev/null; then
      pm2 reload ecosystem.config.js --env production 2>/dev/null || \\
      pm2 restart all 2>/dev/null || \\
      echo "PM2 restart skipped"
    elif [ -f "docker-compose.yml" ]; then
      docker-compose down && docker-compose up -d
    else
      echo "No process manager found. Manual restart may be required."
    fi
  `;

  exec(`ssh ${deployUser}@${deployHost} '${restartCommands}'`, { stdio: 'inherit' });

  // Clean up old releases (keep last 5)
  const cleanupCmd = `
    cd ${deployPath}/releases && \\
    ls -dt */ | tail -n +6 | xargs -r rm -rf
  `;
  exec(`ssh ${deployUser}@${deployHost} '${cleanupCmd}'`, { ignoreError: true });

  logInfo('Old releases cleaned up (keeping last 5)');
}

async function deployDocker() {
  logInfo('Building Docker image...');

  const imageTag = `app:${pipelineState.commitHash.substring(0, 8)}`;
  const latestTag = 'app:latest';

  // Build Docker image
  exec(`docker build -t ${imageTag} -t ${latestTag} .`, { stdio: 'inherit' });

  // Stop existing container
  exec('docker stop app-container 2>/dev/null || true', { ignoreError: true });
  exec('docker rm app-container 2>/dev/null || true', { ignoreError: true });

  // Run new container
  exec(
    `docker run -d --name app-container --restart unless-stopped -p 3000:3000 --env-file .env.production ${latestTag}`,
    { stdio: 'inherit' }
  );

  // Clean up old images (keep last 5)
  exec(
    'docker images app --format "{{.ID}} {{.CreatedAt}}" | sort -k2 -r | tail -n +6 | awk \'{print $1}\' | xargs -r docker rmi',
    { ignoreError: true }
  );

  logInfo(`Docker image: ${imageTag}`);
}

async function deployLocal() {
  logInfo('Deploying locally...');

  const deployDir = CONFIG.deployPath;
  fs.mkdirSync(deployDir, { recursive: true });

  // Copy build files
  if (fileExists(CONFIG.buildDir)) {
    exec(`cp -r ${CONFIG.buildDir}/* ${deployDir}/`);
  }
  exec(`cp package.json ${deployDir}/`);
  if (fileExists('package-lock.json')) {
    exec(`cp package-lock.json ${deployDir}/`);
  }

  // Install production dependencies
  exec(`cd ${deployDir} && npm ci --production --prefer-offline --no-audit --no-fund`, {
    stdio: 'inherit',
  });

  // Write commit hash
  fs.writeFileSync(path.join(deployDir, 'COMMIT_HASH'), pipelineState.commitHash);

  logInfo(`Deployed to ${deployDir}`);
}

async function deployPM2() {
  logInfo('Deploying with PM2...');

  // Check if PM2 is available
  try {
    exec('pm2 --version');
  } catch {
    logInfo('Installing PM2...');
    exec('npm install -g pm2');
  }

  if (fileExists('ecosystem.config.js')) {
    exec('pm2 reload ecosystem.config.js --env production', { stdio: 'inherit' });
  } else {
    // Create a default ecosystem config
    const ecosystemConfig = `
module.exports = {
  apps: [{
    name: '${JSON.parse(fs.readFileSync('package.json', 'utf-8')).name || 'app'}',
    script: '${CONFIG.buildDir}/index.js',
    instances: 'max',
    exec_mode: 'cluster',
    env_production: {
      NODE_ENV: 'production',
      PORT: 3000,
    },
    max_memory_restart: '512M',
    error_file: '/var/log/pm2/error.log',
    out_file: '/var/log/pm2/out.log',
    merge_logs: true,
  }],
};`;
    fs.writeFileSync('ecosystem.config.js', ecosystemConfig);
    exec('pm2 start ecosystem.config.js --env production', { stdio: 'inherit' });
  }

  exec('pm2 save', { stdio: 'inherit' });
  logInfo('PM2 process list:');
  exec('pm2 list', { stdio: 'inherit' });
}

async function healthCheck() {
  await measureStepAsync('Health Check', async () => {
    const url = CONFIG.healthCheckUrl;
    logInfo(`Checking health at: ${url}`);

    for (let i = 1; i <= CONFIG.healthCheckRetries; i++) {
      try {
        const response = exec(`curl -sf -o /dev/null -w "%{http_code}" ${url} 2>/dev/null`, {
          ignoreError: true,
        });

        if (response === '200') {
          logSuccess(`Health check passed (attempt ${i}/${CONFIG.healthCheckRetries})`);
          return;
        }
        logWarning(`Health check returned ${response} (attempt ${i}/${CONFIG.healthCheckRetries})`);
      } catch {
        logWarning(`Health check failed (attempt ${i}/${CONFIG.healthCheckRetries})`);
      }

      if (i < CONFIG.healthCheckRetries) {
        await new Promise((resolve) => setTimeout(resolve, CONFIG.healthCheckInterval));
      }
    }

    throw new Error(`Health check failed after ${CONFIG.healthCheckRetries} attempts`);
  });
}

async function rollback() {
  logStep('🔙 Rolling Back Deployment');

  if (!pipelineState.previousDeployHash) {
    logError('No previous deployment hash found. Cannot rollback.');
    return;
  }

  logInfo(`Rolling back to: ${pipelineState.previousDeployHash.substring(0, 8)}`);

  try {
    switch (CONFIG.deployTarget) {
      case 'remote': {
        const { deployHost, deployUser, deployPath } = CONFIG;
        const currentLink = `${deployPath}/current`;

        // Find the previous release directory
        const rollbackCmd = `
          cd ${deployPath}/releases && \\
          PREV=$(ls -dt */ | sed -n '2p' | sed 's/\\/$//') && \\
          if [ -n "$PREV" ]; then
            ln -sfn ${deployPath}/releases/$PREV ${currentLink} && \\
            cd ${currentLink} && \\
            pm2 reload ecosystem.config.js --env production 2>/dev/null || true && \\
            echo "Rolled back to $PREV"
          else
            echo "No previous release found"
            exit 1
          fi
        `;

        exec(`ssh ${deployUser}@${deployHost} '${rollbackCmd}'`, { stdio: 'inherit' });
        break;
      }

      case 'docker': {
        exec('docker stop app-container 2>/dev/null || true');
        exec('docker rm app-container 2>/dev/null || true');
        const prevImage = `app:${pipelineState.previousDeployHash.substring(0, 8)}`;
        exec(`docker run -d --name app-container --restart unless-stopped -p 3000:3000 ${prevImage}`, {
          stdio: 'inherit',
        });
        break;
      }

      case 'pm2':
        exec('pm2 reload ecosystem.config.js --env production 2>/dev/null || pm2 restart all');
        break;

      default:
        logWarning('Rollback not supported for this deploy target.');
    }

    logSuccess('Rollback completed');
  } catch (error) {
    logError(`Rollback failed: ${error.message}`);
  }
}

async function sendNotification(status) {
  if (!CONFIG.slackWebhook) return;

  try {
    const totalDuration = ((Date.now() - pipelineState.startTime) / 1000).toFixed(2);
    const emoji = status === 'success' ? '✅' : '❌';
    const color = status === 'success' ? '#36a64f' : '#ff0000';

    const stepsSummary = pipelineState.steps
      .map((s) => `${s.status === 'success' ? '✅' : '❌'} ${s.name}: ${s.duration}s`)
      .join('\n');

    const payload = {
      attachments: [
        {
          color,
          title: `${emoji} Deployment ${status.toUpperCase()}`,
          fields: [
            { title: 'Branch', value: pipelineState.branch, short: true },
            { title: 'Commit', value: pipelineState.commitHash.substring(0, 8), short: true },
            { title: 'Environment', value: CONFIG.environment, short: true },
            { title: 'Duration', value: `${totalDuration}s`, short: true },
            { title: 'Steps', value: stepsSummary, short: false },
          ],
          footer: `Deployment Pipeline | ${new Date().toISOString()}`,
        },
      ],
    };

    if (pipelineState.errors.length > 0) {
      payload.attachments[0].fields.push({
        title: 'Errors',
        value: pipelineState.errors.map((e) => `${e.step}: ${e.error}`).join('\n'),
        short: false,
      });
    }

    exec(
      `curl -s -X POST -H 'Content-type: application/json' --data '${JSON.stringify(payload)}' ${CONFIG.slackWebhook}`,
      { ignoreError: true }
    );

    logInfo('Notification sent');
  } catch (error) {
    logWarning(`Failed to send notification: ${error.message}`);
  }
}

function printSummary() {
  const totalDuration = ((Date.now() - pipelineState.startTime) / 1000).toFixed(2);
  const hasErrors = pipelineState.errors.length > 0;

  console.log('\n');
  const separator = '═'.repeat(60);
  console.log(`${hasErrors ? colors.red : colors.green}${separator}`);
  console.log(`  📊 Pipeline Summary`);
  console.log(`${separator}${colors.reset}\n`);

  // Print each step
  for (const step of pipelineState.steps) {
    const icon = step.status === 'success' ? '✅' : '❌';
    const duration = `${step.duration}s`.padStart(8);
    console.log(`  ${icon} ${step.name.padEnd(35)} ${duration}`);
  }

  console.log(`\n  ${'─'.repeat(50)}`);
  console.log(`  Total Duration:${`${totalDuration}s`.padStart(32)}`);
  console.log(`  Commit: ${pipelineState.commitHash.substring(0, 8)}`);
  console.log(`  Branch: ${pipelineState.branch}`);
  console.log(`  Environment: ${CONFIG.environment}`);

  if (hasErrors) {
    console.log(`\n  ${colors.red}Errors:${colors.reset}`);
    for (const error of pipelineState.errors) {
      console.log(`    ❌ ${error.step}: ${error.error}`);
    }
  }

  console.log(`\n${hasErrors ? colors.red : colors.green}${separator}${colors.reset}\n`);
}

// ============================================================================
// Main Pipeline
// ============================================================================

async function runPipeline() {
  console.log(`\n${colors.bold}${colors.cyan}`);
  console.log('╔══════════════════════════════════════════════════════════╗');
  console.log('║             🚀 CI/CD DEPLOYMENT PIPELINE 🚀            ║');
  console.log('╚══════════════════════════════════════════════════════════╝');
  console.log(`${colors.reset}\n`);

  let deploymentSuccessful = false;

  try {
    // Phase 1: Preparation
    gatherInfo();
    validateEnvironment();
    cleanPreviousBuild();

    // Phase 2: Dependencies
    installDependencies();
    runSecurityAudit();

    // Phase 3: Quality Checks (can run some in parallel for speed)
    await measureStepAsync('Quality Checks (Parallel)', async () => {
      const checks = [];

      // Lint and type check can run in parallel
      checks.push(
        runAsync('npm run lint 2>/dev/null || echo "lint skipped"', { silent: true })
          .then(() => logInfo('Linting complete'))
          .catch(() => logWarning('Linting skipped or failed'))
      );

      if (fileExists('tsconfig.json')) {
        checks.push(
          runAsync('npx tsc --noEmit 2>/dev/null || echo "typecheck skipped"', { silent: true })
            .then(() => logInfo('Type check complete'))
            .catch(() => logWarning('Type check skipped or failed'))
        );
      }

      await Promise.allSettled(checks);
      logSuccess('Quality checks completed');
    });

    // Phase 4: Tests
    await runTests();

    // Phase 5: Build
    buildApplication();

    // Phase 6: Create Artifacts
    createArtifacts();

    // Phase 7: Deploy
    await deployApplication();

    // Phase 8: Verify
    try {
      await healthCheck();
      deploymentSuccessful = true;
    } catch (healthError) {
      logError('Health check failed after deployment');

      if (CONFIG.rollbackEnabled) {
        logWarning('Initiating rollback...');
        await rollback();

        // Re-check health after rollback
        try {
          await healthCheck();
          logSuccess('Rollback successful - health check passed');
        } catch {
          logError('Health check failed even after rollback!');
        }
      }

      throw healthError;
    }

    // Success!
    printSummary();
    await sendNotification('success');

    log('\n🎉 Deployment completed successfully!\n', colors.green);
    process.exit(0);
  } catch (error) {
    printSummary();
    await sendNotification('failed');

    logError(`\nPipeline failed: ${error.message}\n`);

    if (!deploymentSuccessful && CONFIG.rollbackEnabled && pipelineState.steps.some((s) => s.name.includes('Deploy'))) {
      logWarning('Deployment may be in an inconsistent state. Check the application.');
    }

    process.exit(1);
  }
}

// Handle uncaught errors
process.on('uncaughtException', async (error) => {
  logError(`Uncaught exception: ${error.message}`);
  await sendNotification('failed');
  process.exit(1);
});

process.on('unhandledRejection', async (error) => {
  logError(`Unhandled rejection: ${error}`);
  await sendNotification('failed');
  process.exit(1);
});

// Handle graceful shutdown
process.on('SIGINT', async () => {
  logWarning('\nPipeline interrupted by user');
  await sendNotification('cancelled');
  process.exit(130);
});

process.on('SIGTERM', async () => {
  logWarning('\nPipeline terminated');
  await sendNotification('cancelled');
  process.exit(143);
});

// Run the pipeline
runPipeline();